#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isValid(string s) {
        stack<char> st;
        unordered_map<char, char> bracket_map = {{')', '('}, {'}', '{'}, {']', '['}};
        for (char bracket : s) {
            if (bracket == '(' || bracket == '{' || bracket == '[') {
                st.push(bracket);
            } else if (bracket == ')' || bracket == '}' || bracket == ']') {
                if (st.empty() || st.top() != bracket_map[bracket]) {
                    return false;
                }
                st.pop();
            }
        }
        return st.empty();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    string s;
    cin >> s;
    Solution sol;
    cout << boolalpha << sol.isValid(s) << '\n';
    return 0;
}
